import{_ as e,o as a,c as t,Q as i}from"./chunks/framework.b67c47e6.js";const m=JSON.parse('{"title":"Stock & Products","description":"","frontmatter":{},"headers":[],"relativePath":"guide/stock/index.md","filePath":"guide/stock/index.md","lastUpdated":1773939149000}'),s={name:"guide/stock/index.md"},r=i('<h1 id="stock-products" tabindex="-1">Stock &amp; Products <a class="header-anchor" href="#stock-products" aria-label="Permalink to &quot;Stock &amp; Products&quot;">​</a></h1><p>The Stock &amp; Products view lets you manage your material catalog — the materials, sizes, and products used across your projects.</p><nav class="table-of-contents"><ul><li><a href="#catalog-sections">Catalog Sections</a><ul><li><a href="#materials">Materials</a></li><li><a href="#plate-sizes">Plate Sizes</a></li><li><a href="#profile-sizes">Profile Sizes</a></li><li><a href="#product-plates">Product Plates</a></li><li><a href="#product-profiles">Product Profiles</a></li></ul></li><li><a href="#managing-catalog-entries">Managing Catalog Entries</a></li><li><a href="#connection-to-other-features">Connection to Other Features</a></li></ul></nav><h2 id="catalog-sections" tabindex="-1">Catalog Sections <a class="header-anchor" href="#catalog-sections" aria-label="Permalink to &quot;Catalog Sections&quot;">​</a></h2><p>The view contains five tables, each managing a different part of your material catalog:</p><h3 id="materials" tabindex="-1">Materials <a class="header-anchor" href="#materials" aria-label="Permalink to &quot;Materials&quot;">​</a></h3><p>The base materials used in production (e.g., types of wood, metal, OSB, plasterboard). Each material entry defines a material type that can be referenced across projects.</p><h3 id="plate-sizes" tabindex="-1">Plate Sizes <a class="header-anchor" href="#plate-sizes" aria-label="Permalink to &quot;Plate Sizes&quot;">​</a></h3><p>Dimensional variants for plate materials. Define the available widths and lengths for each plate material so that reports and logistics can filter by specific sizes.</p><h3 id="profile-sizes" tabindex="-1">Profile Sizes <a class="header-anchor" href="#profile-sizes" aria-label="Permalink to &quot;Profile Sizes&quot;">​</a></h3><p>Dimensional variants for profile materials (structural elements like studs, beams). Define the cross-section dimensions available for each profile material.</p><h3 id="product-plates" tabindex="-1">Product Plates <a class="header-anchor" href="#product-plates" aria-label="Permalink to &quot;Product Plates&quot;">​</a></h3><p>Pre-cut plate products used in assemblies. Each entry combines a material with a specific size and any additional specifications.</p><h3 id="product-profiles" tabindex="-1">Product Profiles <a class="header-anchor" href="#product-profiles" aria-label="Permalink to &quot;Product Profiles&quot;">​</a></h3><p>Pre-cut profile products used in assemblies. Each entry combines a material with a specific cross-section size.</p><h2 id="managing-catalog-entries" tabindex="-1">Managing Catalog Entries <a class="header-anchor" href="#managing-catalog-entries" aria-label="Permalink to &quot;Managing Catalog Entries&quot;">​</a></h2><p>For each table, you can:</p><ul><li><strong>Create</strong> — Add a new entry with its name, dimensions, and specifications.</li><li><strong>Edit</strong> — Modify existing entries.</li><li><strong>Delete</strong> — Remove entries no longer in use.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a material or size that is referenced by existing designs or reports may cause issues. Only remove entries that are no longer needed.</p></div><h2 id="connection-to-other-features" tabindex="-1">Connection to Other Features <a class="header-anchor" href="#connection-to-other-features" aria-label="Permalink to &quot;Connection to Other Features&quot;">​</a></h2><ul><li>The material catalog feeds into <a href="/guide/logistics/">Logistics</a> for tracking material availability.</li><li><a href="/guide/reports/">Reports</a> use material and size data for Bills of Materials and filtering options.</li><li>Machine file generation uses material properties to determine processing parameters.</li></ul>',21),o=[r];function l(n,c,d,h,p,u){return a(),t("div",null,o)}const g=e(s,[["render",l]]);export{m as __pageData,g as default};
